import React, { useEffect, useState } from "react";
import axios from "axios";
import "bootstrap/dist/css/bootstrap.min.css";

export default function Dashboard() {
  const [categorias, setCategorias] = useState([]);
  const [productos, setProductos] = useState([]);
  const [categoriaSeleccionada, setCategoriaSeleccionada] = useState(null);

  // ✅ Obtener nombre desde localStorage
  const nombreUsuario = localStorage.getItem("nombre") || "Usuario";

  useEffect(() => {
    obtenerCategorias();
    obtenerProductos();
  }, []);

  const obtenerCategorias = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/categorias");
      setCategorias(res.data);
    } catch (error) {
      console.error("Error al obtener categorías:", error);
    }
  };

  const obtenerProductos = async (categoria_id = null) => {
    try {
      let url = "http://localhost:5000/api/productos";
      if (categoria_id) url += `/categoria/${categoria_id}`;
      const res = await axios.get(url);
      setProductos(res.data);
    } catch (error) {
      console.error("Error al obtener productos:", error);
    }
  };

  const handleCategoriaClick = (categoria) => {
    setCategoriaSeleccionada(categoria.id);
    obtenerProductos(categoria.id);
  };

  const handleCerrarSesion = () => {
    localStorage.clear();
    window.location.href = "/";
  };

  return (
    <div className="container mt-4">
      {/* ✅ Bienvenida */}
      <div className="d-flex justify-content-between align-items-center mb-4">
        <h2 className="fw-bold">
          👋 Bienvenido, <span className="text-primary">{nombreUsuario}</span>
        </h2>
        <button onClick={handleCerrarSesion} className="btn btn-outline-danger">
          Cerrar sesión
        </button>
      </div>

      {/* ✅ Categorías */}
      <div className="mb-4">
        <h4 className="mb-3">📦 Categorías</h4>
        <div className="d-flex flex-wrap gap-2">
          {categorias.map((cat) => (
            <button
              key={cat.id}
              onClick={() => handleCategoriaClick(cat)}
              className={`btn ${
                categoriaSeleccionada === cat.id
                  ? "btn-primary"
                  : "btn-outline-primary"
              }`}
            >
              {cat.nombre}
            </button>
          ))}
        </div>
      </div>

      {/* ✅ Productos */}
      <div className="card shadow-sm">
        <div className="card-header bg-primary text-white">
          <h5 className="mb-0">🛒 Productos disponibles</h5>
        </div>
        <div className="card-body p-0">
          <table className="table table-striped mb-0">
            <thead className="table-light">
              <tr>
                <th>Nombre</th>
                <th>Descripción</th>
                <th>Precio</th>
                <th>Stock</th>
                <th>Categoría</th>
              </tr>
            </thead>
            <tbody>
              {productos.length > 0 ? (
                productos.map((p) => (
                  <tr key={p.ProductoID}>
                    <td>{p.Nombre}</td>
                    <td>{p.Descripcion}</td>
                    <td>${p.Precio}</td>
                    <td>{p.Stock}</td>
                    <td>{p.CategoriaNombre || "Sin categoría"}</td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan="5" className="text-center py-3">
                    No hay productos disponibles
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
